try {
  const wd = sim.worldData
  if (!wd.__or) wd.__or = { w: 0, g: 0, gT: 0, br: 0, lmx: 0, lmy: 0 }
  const O = wd.__or
  const pdt = Math.min(dt, 0.05)
  const mx = ((wd.mouse_x ?? 256) - 256) / 256
  const my = ((wd.mouse_y ?? 256) - 256) / 256
  // the standing wind: slow breathing sway
  O.w = Math.sin(Date.now ? 0 : 0) // placeholder no-op
  O.w = Math.sin((wd.__t = (wd.__t || 0) + pdt) * 0.5) * 0.6 + Math.sin(wd.__t * 0.23 + 1.7) * 0.4
  // gusts arrive, hold, let go
  O.gT -= pdt
  if (O.gT <= 0) { O.gT = 4 + (wd.__t % 5); O.gTarget = (wd.__t * 7 % 1) * 0.9 }
  O.g += ((O.gTarget || 0) - O.g) * Math.min(1, pdt * 0.8)
  // your cursor is a breath: moving near the plant stirs it
  const speed = Math.hypot(mx - O.lmx, my - O.lmy) / Math.max(pdt, 0.001)
  const near = Math.exp(-Math.abs(mx + 0.05) * 2.0) * Math.exp(-Math.abs(my) * 1.2)
  O.br += (Math.min(1, speed * 0.5) * near - O.br) * Math.min(1, pdt * 3)
  O.lmx = mx; O.lmy = my
  wd.gpuUniforms = [O.w, O.g, mx, my, O.br]
} catch (e) { /* the orchid keeps its poise */ }

