// ── ORCHID v2: a phalaenopsis, studied ──────────────────────────────────────
fn oc_pet(q0: vec2f, c: vec2f, r: vec2f, ang: f32, seed: f32) -> f32 {
  let q = rotate(q0 - c, ang);
  var d = length(q / r) - 1.0;
  let th = atan2(q.y, q.x);
  // organic rim: broad lobing + a faint ruffle, unique per petal
  d += sin(th * 3.0 + seed * 9.1) * 0.045 + sin(th * 8.0 + seed * 23.0) * 0.016;
  return d;
}

// petal paint: SSS-ish body, radial flush, striations, veins, sheen
fn oc_paint(q0: vec2f, c: vec2f, r: vec2f, ang: f32, seed: f32, d: f32, flowerR: f32, t: f32) -> vec3f {
  let q = rotate(q0 - c, ang);
  let inside = clamp(-d * 2.4, 0.0, 1.0);
  // body: cream heart, cooler rim — light leaking through the thin edge
  var pc = mix(vec3f(1.02, 0.97, 1.00), vec3f(0.97, 0.90, 0.96), inside);
  // the flush: magenta breathes outward from the flower's heart
  let flush = smoothstep(0.85, 0.10, flowerR);
  pc = mix(pc, vec3f(0.94, 0.44, 0.72), flush * 0.55);
  // anisotropic striations: cell rows running the petal's length
  let stria = fbm(vec2f(q.x * 5.0, q.y * 42.0) + seed * 7.0, 4);
  pc *= 0.94 + 0.10 * stria;
  // veins: a main rib and curving branches, magenta, fading at the rim
  let vth = atan2(q.y, q.x + 0.6);
  let vein = pow(abs(sin(vth * 13.0 + fbm(q * 3.0 + seed, 3) * 2.2)), 28.0);
  pc = mix(pc, vec3f(0.80, 0.24, 0.55), vein * inside * (0.30 + flush * 0.35));
  // base of the petal warms toward green-gold where it meets the column
  pc = mix(pc, vec3f(0.90, 0.85, 0.55), smoothstep(0.30, 0.05, flowerR) * 0.25);
  // waxy sheen: one soft highlight band per petal, catching the key light
  let sheen = smoothstep(0.35, 0.0, abs(q.x * 0.7 - q.y * 0.7 + 0.18 + sin(seed * 5.0) * 0.1));
  pc += vec3f(0.10, 0.09, 0.10) * sheen * inside;
  // rim translucency: the thin edge glows against the dark room
  pc += vec3f(0.14, 0.08, 0.12) * (1.0 - inside) * 0.55;
  return pc;
}

// one bloom, painted back-to-front with contact shadows between layers
fn oc_bloom(bp: vec2f, s: f32, flutter: f32, seed: f32, t: f32, bg: vec3f) -> vec4f {
  var col = bg;
  var hit = 0.0;
  let p = bp / s;
  let fr = length(p);
  if (fr > 1.6) { return vec4f(0.0); }
  let shOff = vec2f(0.05, 0.07);   // key light upper-left: shadows fall low-right

  // z-order: 3 sepals (back) → 2 grand petals → lip → column
  for (var i = 0; i < 5; i++) {
    let fi = f32(i);
    var ang = 0.0; var rad = vec2f(0.3, 0.5); var off = vec2f(0.0);
    if (i == 0) { ang = 0.0;  off = vec2f(0.0, -0.55);  rad = vec2f(0.26, 0.52); }   // dorsal sepal
    else if (i == 1) { ang = 0.62;  off = vec2f(-0.34, 0.42); rad = vec2f(0.26, 0.44); }  // low sepals
    else if (i == 2) { ang = -0.62; off = vec2f(0.34, 0.42);  rad = vec2f(0.26, 0.44); }
    else if (i == 3) { ang = 1.22;  off = vec2f(-0.56, -0.06); rad = vec2f(0.66, 0.44); } // grand petals
    else { ang = -1.22; off = vec2f(0.56, -0.06); rad = vec2f(0.66, 0.44); }
    let fl = flutter * 0.06 * sin(t * (1.1 + fi * 0.23) + seed * 3.0 + fi * 2.1);
    let offF = off * (1.0 + fl); let angF = ang + fl * 0.6;
    // contact shadow onto whatever is already painted
    let dS = oc_pet(p + shOff, offF, rad, angF, seed + fi);
    col = mix(col, col * 0.55, smoothstep(0.12, -0.02, dS) * 0.5 * hit);
    // the petal itself
    let d = oc_pet(p, offF, rad, angF, seed + fi);
    if (d < 0.0) {
      col = oc_paint(p, offF, rad, angF, seed + fi, d, fr, t);
      hit = 1.0;
    }
    // anti-aliased edge blend
    col = mix(col, oc_paint(p, offF, rad, angF, seed + fi, 0.0, fr, t), smoothstep(0.015, 0.0, abs(d)) * 0.5 * step(0.0, d));
  }

  // the lip: three-lobed, deep magenta, gold throat with wine speckles
  {
    let dS = oc_pet(p + shOff, vec2f(0.0, 0.20), vec2f(0.16, 0.26), 0.0, seed + 9.0);
    col = mix(col, col * 0.5, smoothstep(0.10, -0.02, dS) * 0.55);
    let dm = oc_pet(p, vec2f(0.0, 0.20), vec2f(0.16, 0.26), 0.0, seed + 9.0);
    let dl = oc_pet(p, vec2f(-0.13, 0.26), vec2f(0.10, 0.13), 0.5, seed + 10.0);
    let dr = oc_pet(p, vec2f(0.13, 0.26), vec2f(0.10, 0.13), -0.5, seed + 11.0);
    let d = min(dm, min(dl, dr));
    if (d < 0.0) {
      let inside = clamp(-d * 3.0, 0.0, 1.0);
      var lc = mix(vec3f(0.55, 0.06, 0.30), vec3f(0.88, 0.25, 0.55), inside);
      lc *= 0.9 + 0.2 * fbm(p * 14.0 + seed, 3);
      // the throat: gold, freckled with wine
      let thr = smoothstep(0.14, 0.02, length(p - vec2f(0.0, 0.10)));
      lc = mix(lc, vec3f(1.0, 0.80, 0.30), thr);
      let sp = hash21(floor((p + seed) * 34.0));
      lc = mix(lc, vec3f(0.45, 0.05, 0.22), step(0.78, sp) * thr * 0.8);
      lc += vec3f(0.12) * smoothstep(0.3, 0.0, abs(d + 0.03));   // wet gloss on the lip's crest
      col = lc; hit = 1.0;
    }
  }
  // the column: a pale hood, softly dimensional
  {
    let d = oc_pet(p, vec2f(0.0, -0.02), vec2f(0.075, 0.105), 0.0, seed + 13.0);
    if (d < 0.0) {
      let inside = clamp(-d * 5.0, 0.0, 1.0);
      col = mix(vec3f(0.92, 0.80, 0.86), vec3f(1.02, 0.99, 0.96), inside * (0.6 + 0.4 * smoothstep(0.0, -0.06, p.y)));
      hit = 1.0;
    }
  }
  return vec4f(col, hit);
}

fn visual_orchid(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let sway = uni(0);
  let gust = uni(1);
  let mc = vec2f(uni(2), uni(3));
  let breeze = uni(4);

  // ── the greenhouse at dusk, out of focus ──
  var col = mix(vec3f(0.050, 0.068, 0.052), vec3f(0.115, 0.135, 0.105), 0.5 - 0.5 * uv.y);
  // blurred window light, upper left — the key light's source, visible
  col += vec3f(0.22, 0.20, 0.13) * exp(-dot(uv - vec2f(-0.62, -0.62), uv - vec2f(-0.62, -0.62)) * 2.2);
  // a second orchid far behind, pure defocused silhouette
  {
    let q = rotate(uv - vec2f(0.52, 0.05), 0.2) * vec2f(1.0, 1.4);
    col += vec3f(0.16, 0.10, 0.14) * exp(-dot(q, q) * 9.0) * 0.8;
    col += vec3f(0.12, 0.06, 0.10) * exp(-dot(q - vec2f(0.08, -0.2), q - vec2f(0.08, -0.2)) * 14.0) * 0.7;
  }
  // bokeh discs, hexagonal-soft, three depths
  for (var b = 0; b < 6; b++) {
    let fb = f32(b);
    let bc = vec2f(sin(fb * 2.4 + 1.0) * 0.8, -0.5 + fb * 0.19);
    let bd = length(uv - bc) - (0.05 + fb * 0.012);
    col += vec3f(0.10, 0.11, 0.07) * smoothstep(0.05, -0.01, bd) * (0.35 + 0.1 * sin(t * 0.5 + fb));
  }
  // drifting pollen, catching the light
  let pm = vec2f(uv.x * 9.0 + sin(t * 0.25 + uv.y * 3.0) * 0.4, uv.y * 9.0 + t * 0.07);
  let ph2 = hash21(floor(pm));
  col += vec3f(0.7, 0.62, 0.4) * step(0.982, ph2) * smoothstep(0.28, 0.03, length(fract(pm) - 0.5)) * 0.30;

  // ── the sway, with inertia: the tip remembers the wind a beat late ──
  let hgt = clamp((0.55 - uv.y) / 1.1, 0.0, 1.0);
  let bendNow = (sway * 0.5 + gust * 0.9 + breeze * 0.9) * 0.14;
  let bendLag = (sin(t * 0.5 - 0.6) * 0.6 + sin(t * 0.23 + 1.1) * 0.4) * 0.5 * 0.14 + (gust + breeze) * 0.11;
  let bend = mix(bendNow, bendLag, hgt);   // the higher, the more it lags
  var pp = uv - vec2f(-0.05, 0.62);
  pp = rotate(pp, -bend * hgt * hgt * 2.2);

  // ── leaves: broad, keeled, glossy, parallel-veined ──
  for (var lf = 0; lf < 3; lf++) {
    let f2 = f32(lf);
    let la = -0.9 + f2 * 0.85 + sin(t * 0.6 + f2) * 0.012;
    let lc0 = vec2f(cos(la) * 0.36, -0.01 + abs(sin(la)) * 0.05);
    let d = oc_pet(pp, lc0, vec2f(0.38, 0.125), la * 0.55, f2 * 31.0);
    if (d < 0.0) {
      let q = rotate(pp - lc0, la * 0.55);
      let inside = clamp(-d * 2.0, 0.0, 1.0);
      var g = mix(vec3f(0.030, 0.115, 0.045), vec3f(0.10, 0.30, 0.11), inside);
      // parallel venation running the blade
      g *= 0.88 + 0.18 * pow(abs(sin(q.y * 46.0 + q.x * 3.0)), 0.6);
      // keel: the center fold catches the light on one side
      g += vec3f(0.10, 0.16, 0.09) * smoothstep(0.05, 0.0, abs(q.y)) * 0.8;
      g *= 1.0 + 0.35 * smoothstep(0.2, -0.4, q.x + q.y);   // gloss toward the light
      // dark contact shade where the leaf meets the crown
      g *= 1.0 - 0.5 * smoothstep(0.18, 0.02, length(pp));
      col = mix(col, g, smoothstep(0.012, -0.012, d));
    }
  }

  // ── the stem: a raceme arcing up, with nodes and a dew sheen ──
  {
    let sx = pow(clamp(-pp.y / 1.05, 0.0, 1.0), 1.7) * 0.34 + sin(pp.y * 2.2 + t * 0.7) * 0.003;
    let w = 0.017 - clamp(-pp.y, 0.0, 1.0) * 0.009;
    let sd = abs(pp.x - sx) - w;
    if (pp.y < 0.06 && pp.y > -1.13 && sd < 0.0) {
      var sc = mix(vec3f(0.10, 0.24, 0.09), vec3f(0.32, 0.48, 0.20), clamp(-sd / w, 0.0, 1.0));
      sc *= 0.92 + 0.10 * fbm(pp * 30.0, 3);
      sc += vec3f(0.20, 0.22, 0.12) * smoothstep(0.4, 0.0, abs(pp.x - sx + w * 0.5) / w);   // cylinder highlight
      let node = smoothstep(0.012, 0.0, abs(fract(pp.y * 4.0 + 0.3) - 0.5) * 0.5 - 0.23);
      sc *= 1.0 - node * 0.25;
      col = mix(col, sc, smoothstep(0.004, -0.004, sd));
    }
  }

  // ── pedicels, then blooms, back-to-front so the front flower owns its edge ──
  for (var k = 3; k >= 0; k--) {
    let fk = f32(k);
    let by = -0.42 - fk * 0.235;
    let bx0 = pow(clamp(-by / 1.05, 0.0, 1.0), 1.7) * 0.34;
    let bx = bx0 + 0.11 + sin(fk * 2.1) * 0.05;
    // pedicel: a slim curve from stem to bloom
    {
      let mid = vec2f((bx0 + bx) * 0.5, by + 0.03);
      let pd = length(pp - mid) - 0.058;
      let band = abs((pp.y - by) - (pp.x - bx) * ((by + 0.03 - by) / max(bx0 - bx, 0.02))) - 0.008;
      let seg = max(band, pd);
      if (seg < 0.0) { col = mix(col, vec3f(0.16, 0.30, 0.12), smoothstep(0.006, -0.006, seg)); }
    }
    let bs = 0.16 - fk * 0.013;
    let flut = 0.35 + gust * 1.1 + breeze * 0.8;
    let bp = rotate(pp - vec2f(bx, by), sin(t * (0.9 + fk * 0.13) + fk * 1.7) * 0.045 * flut + bend * 0.6);
    let bloom = oc_bloom(bp, bs, flut, fk * 3.7 + 1.0, t, col);
    col = mix(col, bloom.rgb, bloom.a);
  }

  // buds at the tip: jade teardrops, seam blushing
  for (var bu = 0; bu < 2; bu++) {
    let fb2 = f32(bu);
    let by2 = -1.03 - fb2 * 0.085;
    let bx2 = pow(clamp(-by2 / 1.05, 0.0, 1.0), 1.7) * 0.34 + 0.045 + fb2 * 0.03;
    let d = oc_pet(pp, vec2f(bx2, by2), vec2f(0.030 - fb2 * 0.008, 0.046 - fb2 * 0.011), 0.4, 51.0 + fb2)
;    if (d < 0.0) {
      let inside = clamp(-d * 5.0, 0.0, 1.0);
      var bc2 = mix(vec3f(0.22, 0.36, 0.16), vec3f(0.52, 0.58, 0.30), inside);
      bc2 *= 0.9 + 0.2 * fbm(pp * 40.0, 3);
      bc2 = mix(bc2, vec3f(0.85, 0.45, 0.62), smoothstep(0.015, 0.0, abs(pp.x - bx2)) * 0.45);
      bc2 += vec3f(0.18) * smoothstep(0.02, 0.0, length(pp - vec2f(bx2 - 0.008, by2 - 0.012)));   // dew point
      col = mix(col, bc2, smoothstep(0.006, -0.006, d));
    }
  }

  // your breath, barely: a shimmer of moved air
  col += vec3f(0.5, 0.55, 0.45) * exp(-dot(uv - mc, uv - mc) * 500.0) * breeze * 0.10;

  // film grain + gentle vignette: the photograph, not the diagram
  col *= 0.97 + 0.06 * hash21(uv * 700.0 + fract(t) * 37.0);
  col *= 1.0 - 0.38 * pow(length(uv) * 0.75, 3.0);
  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.05); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
}
